import { useParams } from "react-router-dom";
import { useEffect, useState } from "react";

function OfferLetter() {
  const { applicationId } = useParams();
  const [application, setApplication] = useState(null);

  /* =========================
     LOAD APPLICATION
  ========================= */
  useEffect(() => {
    const apps =
      JSON.parse(localStorage.getItem("applications")) || [];

    const found = apps.find(
      a => String(a.id) === String(applicationId)
    );

    setApplication(found);
  }, [applicationId]);

  if (!application) {
    return <p style={{ marginTop: "25px" }}>Loading offer details…</p>;
  }

  return (
    <div className="designation-container">
      <h2>Generate Offer Letter</h2>

      {/* =========================
         CANDIDATE DETAILS (READ ONLY)
      ========================= */}
      <div className="designation-form">
        <input
          type="text"
          value={application.employeeName || "N/A"}
          disabled
          placeholder="Candidate Name"
        />

        <input
          type="text"
          value={application.email}
          disabled
          placeholder="Email"
        />

        <input
          type="text"
          value={application.jobTitle}
          disabled
          placeholder="Job Title"
        />
      </div>

      <hr style={{ margin: "25px 0" }} />

      {/* =========================
         OFFER DETAILS (FORM)
      ========================= */}
      <div className="designation-form">

        <input
          type="number"
          placeholder="Annual CTC (₹)"
        />

        <input
          type="date"
          placeholder="Date of Joining"
        />

        <input
          type="text"
          placeholder="Work Location"
        />

        <input
          type="text"
          placeholder="Reporting Manager"
        />

        <select>
          <option value="">Employment Type</option>
          <option>Permanent</option>
          <option>Contract</option>
          <option>Intern</option>
        </select>

        <textarea
          placeholder="Additional Notes (Optional)"
          rows="3"
        />

        <button style={{ background: "#2563eb" }}>
          Generate Offer Letter
        </button>
      </div>
    </div>
  );
}

export default OfferLetter;
